import React, { Component } from 'react';
import './blogs.css';
import Simplelayout from '../../../utils/component/simplelayout/simplelayout';
import Blogcard from '../component/blogcard';
import Navbar from '../component/navbar';

export default class Blogs extends Component {
  constructor(props) {
    super(props);
    this.state = {
        content : null
    }

    fetch("/blog/metadata.json")
        .then(r=> r.json())
        .then(r=> this.setState({content:r}));
  }


  render() { 
    let c = this.state.content;
    let articles = [];
    let tags = [];
    if (c !== null) {
        c = c.articles;
        for (let i=0; i<c.length; i++) {
            let a = c[i];
            let newdiv = (
                <Blogcard key={i}
                    title={a.title}
                    description={a.description}
                    date={a.date}
                    tags={a.tags}
                    path={a.pagepath}/>
            );
            articles.push(newdiv);
            a.tags.forEach(x => {
                if (!tags.includes(x)) {
                    tags.push(x);
                }
            });
            
        }
    }

    let layoutArray = [
        (<Navbar key="navbar" items={tags.map(x=>{return {value:x, iconClass:"fa fa-tag"}})}/>),
        (<div key="blogs" className="Blogs">
            {articles}
        </div>)
    ];

    return (
        <Simplelayout content={layoutArray}/>
    );
  }
}
