import React, { Component } from 'react';
import './blogcard.css';

export default class Blogcard extends Component {
  render() {
    return (
      <div className="Blogcard">
        <div className="Blogcard-body">
          <div className="Blogcard-header">{this.props.title}</div>
          <div className="Blogcard-tags">{this.props.tags.join(", ")}</div>
          <div className="Blogcard-description">{this.props.description}</div>
          <div className="Blogcard-datetime">{this.props.date}</div>
        </div>
        <div className="Blogcard-navigator" onClick={()=>{window.location = this.props.path}}>
          <i className="fa fa-angle-right" aria-hidden="true"></i>
        </div>
      </div>
    );
  }
}
