import React, { Component } from 'react';
import ReactMarkdown from 'react-markdown';
import './blogdetail.css';
import Navbar from '../component/navbar';
import Loader from '../../../utils/component/loader/loader';
import Simplelayout from '../../../utils/component/simplelayout/simplelayout';
import Alert from '../../../utils/component/alert/alert';

export default class BlogDetail extends Component {
  constructor(props) {
    super(props);
    this.state = {
      content: null,
      error: 0,
      alert: 0,
      navbarItems: [
        { value: 'Go To Main', iconClass: 'fa fa-home', loc: "/" },
        { value: 'Go To Blog', iconClass: 'fa fa-newspaper-o', loc: "/?p=blogs" },
        { value: 'Share', iconClass: 'fa fa-share-alt', farOnClick: () => {
            let url = document.getElementById("paste-box");
            url.value = window.location.href;
            url.focus();
            url.type = 'text';
            url.select();
            url.setSelectionRange(0, 99999);
            document.execCommand("copy");
            url.type = 'hidden';
            this.setState({ alert: 1 });
            setTimeout(() => {
              this.setState({ alert: 0 });
            }, 1000);
          }
        },
      ]
    }
  }

  componentDidMount() {
    let url = new URL(window.location.href);
    let a = url.searchParams.get("a");

    if (a === null) {
      this.setState({ error: 1 });
    }

    fetch("/blog/" + a + ".md")
      .then((r) => { return r.text(); })
      .then((r) => {
        if (r.startsWith("<!DOC")) {
          this.setState({ error: 1 });
        } else {
          this.setState({ content: r })
        }
      });
  }

  render() {
    let c = this.state.content;

    if (this.state.error === 1) {
      c = (<h1>BLOG NOT FOUND! GO TO BLOGS PAGE</h1>);
    } else if (c !== null) {
      c = (<ReactMarkdown source={c} />);
    } else {
      c = (<Loader />);
    }

    let layoutContent = [
      (<Navbar key="navbar" items={this.state.navbarItems} />),
      (<div key="maincontent" className="BlogDetail-Content" style={{ height: (height - 75) + "px" }}>
        {c}
      </div>),
      (<input key="hiddeninput" type="hidden" id="paste-box" />)
    ];

    if (this.state.alert !== 0) {
      layoutContent.push(<Alert />);
    }

    return (
      <Simplelayout content={layoutContent} />
    );
  }
}

const height = window.innerHeight;
