import React, { Component } from 'react';
import {promises} from '../script/dash_proms';
import './dash_add.css';

export default class DashAdd extends Component {
    constructor(props) {
        super(props);

        this.state = {
            tag : "",
            link : ""
        };

        this.onClickSave = this.onClickSave.bind(this);
        this.closeAdding = this.closeAdding.bind(this);
    }

    onClickSave() {
        promises.items_get().then(res => {
            let r = res;
            let l = this.state.link;
            if (!l.startsWith("https://") && !l.startsWith("http://")) {
                l = "http://" + l;
            }
            r.push({ tag: this.state.tag, link: l });
            promises.items_set(r).then(res => {
                this.props.farOnClickSave(r);
            });
        });
    }

    closeAdding() {
        this.setState({
            tag: "",
            link: ""
        });

        this.props.farCloseAdding();
    }

    render() {
        return (
            <div className="Dash">
                <div className="Dash-Header">
                    <div className="Dash-Header-Item" onClick={this.closeAdding}>close</div>
                    <div className="Dash-Header-Item" onClick={this.onClickSave}>save</div>
                </div>
                <div className="Dash-Content" style={{ height: (height - 50) + "px" }}>
                    <div className="Dash-Item">
                        <label>tag :</label>
                        <input value={this.state.tag} onChange={(e) => this.setState({ tag: e.target.value })} />
                    </div>
                    <div className="Dash-Item">
                        <label>link :</label>
                        <input value={this.state.link} onChange={(e) => this.setState({ link: e.target.value })} />
                    </div>
                </div>
            </div>
        );
    }
}

const height = window.innerHeight;