import React, { Component } from 'react';
import './greetingmenu.css';

export default class Greetingmenu extends Component {
  
  onclick(loc) {
    if (loc !== null) {
        window.location = loc;
    }
  }

  render() {
    return (
      <div className="Greetingmenu">
          <div className="Greetingmenuitem blue" onClick={()=>{this.onclick(null);}}>about.me</div>
          <div className="Greetingmenuitem red" onClick={()=>{this.onclick("/?p=blogs");}}>blog</div>
          <div className="Greetingmenuitem yellow" onClick={()=>{this.onclick(null);}}>project</div>
          <div className="Greetingmenuitem green" onClick={()=>{this.onclick(null);}}>studio</div>
      </div>
    );
  }
}
