import React, { Component } from 'react';
import AdSense from 'react-adsense';
import './simplelayout.css';
import Loader from '../loader/loader';

export default class Simplelayout extends Component {
  constructor(props) {
    super(props);
    this.state = {
      loading : props.isLoading
    }
  }

  render() {
    let content = null;
    if (this.props.isLoading) {
      content = <Loader />
    } else {
      content = this.props.content;
    }

    let adswidth = Math.floor((_W-720)/2);

    return (
      <div className="Simplelayout">

        <div className="SimpleAdSense" style={{width: adswidth, height: "100%"}}>
          <AdSense.Google
            client='ca-pub-8365849920887056'
            slot='1234567'
            style={{width: adswidth, float: "left"}}
            format=''
          />
        </div>


        <div className="SimpleContent">
          {content}
        </div>

        <div className="SimpleAdSense" style={{width: adswidth, height: "100%"}}>
          <AdSense.Google
            client='ca-pub-8365849920887056'
            slot='1234567'
            style={{width: adswidth, float: "left"}}
            format=''
          />
        </div>
      </div>
    );
  }
}

const _W = window.innerWidth;