import React, { Component } from 'react';
import './navbar.css';
import Dabutton from './dabutton';


export default class Navbar extends Component {
  
    render() {

        let items = this.props.items;
        let itemsR = [];
        items.forEach((e,i)=>{
            let onclick = function() {};
            if (e.loc !== undefined) {
                onclick = function() {
                    window.location = e.loc;
                }
            } else if (e.farOnClick !== undefined) {
                onclick = e.farOnClick;
            }
            itemsR.push(
                <Dabutton key={i} value={e.value} iconClass={e.iconClass} farOnClick={onclick} />
            );
        });
        

        return (
        <div className="Navbar">
            {itemsR}
        </div>
        );
    }
}
